// src/pages/LeaveBalance.js
import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { LEAVE_BALANCES } from '../data/initialData';

export default function LeaveBalance() {
  const { currentUser, staff, leaveRequests } = useApp();
  const [selected, setSelected] = useState(null);

  const isAdmin = currentUser.role === 'admin';
  const staffToShow = isAdmin ? staff : staff.filter(t => t.id === currentUser.id);

  // ✅ Seedha staff state se balance lo
  const getBalance = (teacher, type) => {
    const isDuty = type === 'duty';
    const total = LEAVE_BALANCES[type].total;
    const remaining = isDuty ? '∞' : (teacher.leaveBalance?.[type] ?? total);
    const used = isDuty ? 0 : total - (teacher.leaveBalance?.[type] ?? total);
    return { remaining, used };
  };

  // History ke liye leaveRequests use karo
  const getLeavesByType = (teacherId, type) =>
    leaveRequests.filter(r =>
      r.teacherId === teacherId &&
      r.status === 'approved' &&
      r.reason?.toLowerCase().includes(type)
    );

  const handleCardClick = (teacherId, type) => {
    if (selected?.teacherId === teacherId && selected?.type === type) {
      setSelected(null);
    } else {
      setSelected({ teacherId, type });
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>📊 Leave Balance</h1>
        <p style={styles.subtitle}>
          {isAdmin ? 'All faculty leave balances' : 'Your remaining leave balance'}
        </p>
      </div>

      {staffToShow.map(teacher => (
        <div key={teacher.id} style={styles.card}>
          {/* Teacher Header */}
          <div style={styles.cardHeader}>
            <div style={styles.avatar}>{teacher.name[0]}</div>
            <div>
              <div style={styles.teacherName}>{teacher.name}</div>
              <div style={styles.dept}>{teacher.department} | {teacher.subject}</div>
            </div>
          </div>

          {/* Balance Cards */}
          <div style={styles.balanceGrid}>
            {Object.entries(LEAVE_BALANCES).map(([type, info]) => {
              const { remaining, used } = getBalance(teacher, type);
              const isDuty = type === 'duty';
              const percent = isDuty ? 100 : Math.round(
                ((teacher.leaveBalance?.[type] ?? info.total) / info.total) * 100
              );
              const isLow = !isDuty && remaining !== '∞' && remaining <= 3;
              const isActive = selected?.teacherId === teacher.id && selected?.type === type;

              return (
                <div
                  key={type}
                  onClick={() => handleCardClick(teacher.id, type)}
                  style={{
                    ...styles.balanceCard,
                    borderTop: `4px solid ${info.color}`,
                    cursor: 'pointer',
                    boxShadow: isActive ? `0 0 0 2px ${info.color}` : 'none',
                    background: isActive ? '#f0f9ff' : '#f8fafc',
                    transform: isActive ? 'scale(1.02)' : 'scale(1)',
                    transition: 'all 0.2s',
                  }}
                >
                  <div style={styles.balanceIcon}>{info.icon}</div>
                  <div style={styles.balanceLabel}>{info.label}</div>
                  <div style={styles.balanceNumbers}>
                    <span style={{ ...styles.remaining, color: isLow ? '#ef4444' : info.color }}>
                      {remaining}
                    </span>
                    <span style={styles.total}>/ {isDuty ? '∞' : info.total}</span>
                  </div>
                  {!isDuty && (
                    <>
                      <div style={styles.progressBg}>
                        <div style={{
                          ...styles.progressFill,
                          width: `${percent}%`,
                          background: isLow ? '#ef4444' : info.color,
                        }} />
                      </div>
                      <div style={styles.usedText}>Used: {used} day(s)</div>
                      {isLow && <div style={styles.lowWarning}>⚠ Low balance!</div>}
                    </>
                  )}
                  <div style={{ ...styles.clickHint, color: info.color }}>
                    {isActive ? '▲ Hide History' : '▼ View History'}
                  </div>
                </div>
              );
            })}
          </div>

          {/* ✅ Leave History */}
          {selected?.teacherId === teacher.id && (
            <div style={styles.historySection}>
              <h3 style={{
                ...styles.historyTitle,
                color: LEAVE_BALANCES[selected.type]?.color,
              }}>
                {LEAVE_BALANCES[selected.type]?.icon} {LEAVE_BALANCES[selected.type]?.label} — History
              </h3>

              {getLeavesByType(teacher.id, selected.type).length === 0 ? (
                <div style={styles.noHistory}>
                  No {LEAVE_BALANCES[selected.type]?.label} taken yet
                </div>
              ) : (
                <table style={styles.table}>
                  <thead>
                    <tr>
                      {['From', 'To', 'Days', 'Reason', 'Status'].map(h => (
                        <th key={h} style={styles.th}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {getLeavesByType(teacher.id, selected.type).map((r, i) => {
                      const days = Math.ceil(
                        (new Date(r.toDate) - new Date(r.fromDate)) / (1000 * 60 * 60 * 24)
                      ) + 1;
                      return (
                        <tr key={i} style={styles.tr}>
                          <td style={styles.td}>{r.fromDate}</td>
                          <td style={styles.td}>{r.toDate}</td>
                          <td style={styles.td}>
                            <span style={styles.daysBadge}>{days} day(s)</span>
                          </td>
                          <td style={styles.td}>{r.reason}</td>
                          <td style={styles.td}>
                            <span style={styles.approvedBadge}>✅ Approved</span>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              )}
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

const styles = {
  container: { padding: 32, maxWidth: 1100, margin: '0 auto' },
  header: { marginBottom: 28 },
  title: { fontSize: 28, fontWeight: 800, color: '#1e293b', margin: 0 },
  subtitle: { color: '#64748b', marginTop: 6 },
  card: {
    background: '#fff', borderRadius: 20, padding: 28,
    boxShadow: '0 2px 20px rgba(0,0,0,0.06)',
    border: '1px solid #f1f5f9', marginBottom: 24,
  },
